class TransactionManager {
    static let shared = TransactionManager()
    
    private var accounts: [Account] = []
    private var transactions: [Transaction] = []
    
    private let accountsKey = "encrypted_accounts"
    private let transactionsKey = "encrypted_transactions"
    
    init() {
        loadData()
    }
    
    func loadData() {
        if let accountsData = SecureStorage.shared.loadSecurely(forKey: accountsKey) {
            accounts = (try? JSONDecoder().decode([Account].self, from: accountsData)) ?? []
        }
        
        if let transactionsData = SecureStorage.shared.loadSecurely(forKey: transactionsKey) {
            transactions = (try? JSONDecoder().decode([Transaction].self, from: transactionsData)) ?? []
        }
        
        if accounts.isEmpty {
            initializeSampleData()
        }
    }
    
    private func initializeSampleData() {
        accounts = [
            Account(id: UUID().uuidString, balance: 5000.00, accountNumber: "****1234", accountType: .checking),
            Account(id: UUID().uuidString, balance: 15000.00, accountNumber: "****5678", accountType: .savings),
            Account(id: UUID().uuidString, balance: -2500.00, accountNumber: "****9012", accountType: .credit)
        ]
        saveData()
    }
    
    private func saveData() {
        if let accountsData = try? JSONEncoder().encode(accounts) {
            _ = SecureStorage.shared.saveSecurely(accountsData, forKey: accountsKey)
        }
        
        if let transactionsData = try? JSONEncoder().encode(transactions) {
            _ = SecureStorage.shared.saveSecurely(transactionsData, forKey: transactionsKey)
        }
    }
    
    func getAccounts() -> [Account] {
        return accounts
    }
    
    func getTransactions(for accountId: String? = nil) -> [Transaction] {
        if let accountId = accountId {
            return transactions.filter { $0.fromAccountId == accountId || $0.toAccountId == accountId }
        }
        return transactions
    }
    
    func processTransaction(fromAccountId: String, toAccountId: String?, amount: Decimal, type: Transaction.TransactionType, description: String, completion: @escaping (Bool, String) -> Void) {
        guard amount > 0 else {
            completion(false, "Invalid amount")
            return
        }
        
        guard let accountIndex = accounts.firstIndex(where: { $0.id == fromAccountId }) else {
            completion(false, "Account not found")
            return
        }
        
        var fromAccount = accounts[accountIndex]
        
        if type == .withdrawal || type == .transfer || type == .payment {
            guard fromAccount.balance >= amount else {
                completion(false, "Insufficient funds")
                return
            }
        }
        
        let transaction = Transaction(
            id: UUID().uuidString,
            fromAccountId: fromAccountId,
            toAccountId: toAccountId,
            amount: amount,
            type: type,
            date: Date(),
            description: description,
            status: .pending
        )
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            Thread.sleep(forTimeInterval: 1.0)
            
            DispatchQueue.main.async {
                guard let self = self else { return }
                
                switch type {
                case .deposit:
                    fromAccount.balance += amount
                case .withdrawal, .payment:
                    fromAccount.balance -= amount
                case .transfer:
                    if let toAccountId = toAccountId,
                       let toAccountIndex = self.accounts.firstIndex(where: { $0.id == toAccountId }) {
                        var toAccount = self.accounts[toAccountIndex]
                        fromAccount.balance -= amount
                        toAccount.balance += amount
                        self.accounts[toAccountIndex] = toAccount
                    } else {
                        completion(false, "Destination account not found")
                        return
                    }
                }
                
                self.accounts[accountIndex] = fromAccount
                
                var completedTransaction = transaction
                completedTransaction.status = .completed
                self.transactions.insert(completedTransaction, at: 0)
                
                self.saveData()
                
                completion(true, "Transaction completed successfully")
            }
        }
    }
