class NewTransactionViewController: UIViewController {
    
    weak var delegate: NewTransactionDelegate?
    private let account: Account
    
    private let amountTextField = UITextField()
    private let descriptionTextField = UITextField()
    private let typeSegmentedControl = UISegmentedControl(items: ["Deposit", "Withdrawal", "Payment"])
    private let submitButton = UIButton(type: .system)
    
    init(account: Account) {
        self.account = account
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        title = "New Transaction"
        view.backgroundColor = .systemBackground
        
        setupViews()
        setupNavigationBar()
    }
    
    private func setupNavigationBar() {
        let cancelButton = UIBarButtonItem(barButtonSystemItem: .cancel, target: self, action: #selector(cancel))
        navigationItem.leftBarButtonItem = cancelButton
    }
    
    private func setupViews() {
        amountTextField.placeholder = "Amount"
        amountTextField.borderStyle = .roundedRect
        amountTextField.keyboardType = .decimalPad
        
        descriptionTextField.placeholder = "Description"
        descriptionTextField.borderStyle = .roundedRect
        
        typeSegmentedControl.selectedSegmentIndex = 0
        
        submitButton.setTitle("Submit Transaction", for: .normal)
        submitButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .semibold)
        submitButton.backgroundColor = .systemBlue
        submitButton.setTitleColor(.white, for: .normal)
        submitButton.layer.cornerRadius = 8
        submitButton.addTarget(self, action: #selector(submitTransaction), for: .touchUpInside)
        
        view.addSubview(amountTextField)
        view.addSubview(descriptionTextField)
        view.addSubview(typeSegmentedControl)
        view.addSubview(submitButton)
        
        amountTextField.translatesAutoresizingMaskIntoConstraints = false
        descriptionTextField.translatesAutoresizingMaskIntoConstraints = false
        typeSegmentedControl.translatesAutoresizingMaskIntoConstraints = false
        submitButton.translatesAutoresizingMaskIntoConstraints = false
        
        NSLayoutConstraint.activate([
            amountTextField.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            amountTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            amountTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            amountTextField.heightAnchor.constraint(equalToConstant: 44),
            
            descriptionTextField.topAnchor.constraint(equalTo: amountTextField.bottomAnchor, constant: 16),
            descriptionTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            descriptionTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            descriptionTextField.heightAnchor.constraint(equalToConstant: 44),
            
            typeSegmentedControl.topAnchor.constraint(equalTo: descriptionTextField.bottomAnchor, constant: 16),
            typeSegmentedControl.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            typeSegmentedControl.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            submitButton.topAnchor.constraint(equalTo: typeSegmentedControl.bottomAnchor, constant: 32),
            submitButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            submitButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            submitButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    @objc private func cancel() {
        dismiss(animated: true)
    }
    
    @objc private func submitTransaction() {
        guard let amountText = amountTextField.text,
              let amount = Decimal(string: amountText),
              amount > 0 else {
            showAlert(title: "Invalid Amount", message: "Please enter a valid amount")
            return
        }
        
        let description = descriptionTextField.text?.isEmpty == false ? descriptionTextField.text! : "Transaction"
        
        let transactionType: Transaction.TransactionType
        switch typeSegmentedControl.selectedSegmentIndex {
        case 0:
            transactionType = .deposit
        case 1:
            transactionType = .withdrawal
        case 2:
            transactionType = .payment
        default:
            transactionType = .deposit
        }
        
        submitButton.isEnabled = false
        submitButton.setTitle("Processing...", for: .normal)
        
        TransactionManager.shared.processTransaction(
            fromAccountId: account.id,
            toAccountId: nil,
            amount: amount,
            type: transactionType,
            description: description
        ) { [weak self] success, message in
            self?.submitButton.isEnabled = true
            self?.submitButton.setTitle("Submit Transaction", for: .normal)
            
            if success {
                self?.delegate?.didCompleteTransaction()
                self?.showAlert(title: "Success", message: message) {
                    self?.dismiss(animated: true)
                }
            } else {
                self?.showAlert(title: "Error", message: message)
            }
        }
    }
    
    private func showAlert(title: String, message: String, completion: (() -> Void)? = nil) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completion?()
        })
        present(alert, animated: true)
    }
}